from typing import Union, Optional
from dataclasses import dataclass


@dataclass
class ASTNode:
    type: str
    value: Optional[float] = None
    op: Optional[str] = None
    left: Optional["ASTNode"] = None
    right: Optional["ASTNode"] = None
    operand: Optional["ASTNode"] = None


class ExpressionParser:
    def __init__(self):
        self.tokens = []
        self.current_pos = 0

    def parse(self, expression: str) -> ASTNode:
        if not expression.strip():
            raise ValueError("Empty input")

        self.tokens = list(expression.replace(" ", ""))
        self.current_pos = 0

        result = self._parse_expression()

        if self.current_pos < len(self.tokens):
            raise ValueError(
                f"Invalid token at position {self.current_pos}: '{self.tokens[self.current_pos]}'"
            )

        return result

    def _parse_expression(self) -> ASTNode:
        return self._parse_addition()

    def _parse_addition(self) -> ASTNode:
        node = self._parse_multiplication()

        while self.current_pos < len(self.tokens) and self.tokens[self.current_pos] in (
            "+",
            "-",
        ):
            op = self.tokens[self.current_pos]
            self.current_pos += 1
            try:
                right = self._parse_multiplication()
                node = ASTNode(type="binop", op=op, left=node, right=right)
            except ValueError:
                raise ValueError(
                    f"Missing operand for operator '{op}' at position {self.current_pos}"
                )

        return node

    def _parse_multiplication(self) -> ASTNode:
        node = self._parse_unary()

        while self.current_pos < len(self.tokens) and self.tokens[self.current_pos] in (
            "*",
            "/",
        ):
            op = self.tokens[self.current_pos]
            self.current_pos += 1
            right = self._parse_unary()
            node = ASTNode(type="binop", op=op, left=node, right=right)

        return node

    def _parse_unary(self) -> ASTNode:
        if self.current_pos < len(self.tokens) and self.tokens[self.current_pos] == "-":
            op = self.tokens[self.current_pos]
            self.current_pos += 1
            operand = self._parse_unary()
            return ASTNode(type="unary", op=op, operand=operand)

        return self._parse_primary()

    def _parse_primary(self) -> ASTNode:
        if self.current_pos >= len(self.tokens):
            raise ValueError("Unexpected end of expression")

        token = self.tokens[self.current_pos]

        if token == "(":
            self.current_pos += 1
            node = self._parse_expression()
            if (
                self.current_pos >= len(self.tokens)
                or self.tokens[self.current_pos] != ")"
            ):
                raise ValueError("Unmatched parentheses")
            self.current_pos += 1
            return node
        elif token.isdigit() or (
            token == "."
            and self.current_pos + 1 < len(self.tokens)
            and self.tokens[self.current_pos + 1].isdigit()
        ):
            return self._parse_number()
        else:
            raise ValueError(f"Invalid token: '{token}'")

    def _parse_number(self) -> ASTNode:
        start_pos = self.current_pos

        while self.current_pos < len(self.tokens) and (
            self.tokens[self.current_pos].isdigit()
            or self.tokens[self.current_pos] == "."
        ):
            self.current_pos += 1

        number_str = "".join(self.tokens[start_pos : self.current_pos])

        try:
            value = float(number_str)
            return ASTNode(type="number", value=value)
        except ValueError:
            raise ValueError(f"Invalid number format: '{number_str}'")


def parse(expression: str) -> ASTNode:
    parser = ExpressionParser()
    return parser.parse(expression)


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        if node.value is None:
            raise ValueError("Number node has no value")
        return node.value
    elif node.type == "binop":
        if node.left is None or node.right is None:
            raise ValueError("Binary operation node missing operands")
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        else:
            raise ValueError(f"Unknown binary operator: {node.op}")
    elif node.type == "unary":
        if node.operand is None:
            raise ValueError("Unary operation node missing operand")
        operand_val = evaluate(node.operand)
        if node.op == "-":
            return -operand_val
        else:
            raise ValueError(f"Unknown unary operator: {node.op}")
    else:
        raise ValueError(f"Unknown node type: {node.type}")
